import{_ as o,o as t,c as a,ae as l}from"./chunks/framework.BEtfQoF7.js";const p=JSON.parse('{"title":"Remote Control로 어디서나 로컬 세션 계속하기","description":"Remote Control을 사용해 전화기, 태블릿, 또는 모든 브라우저에서 로컬 Claude Code 세션을 이어서 작업하세요. claude.ai/code 및 Claude 모바일 앱에서 작동합니다.","frontmatter":{"title":"Remote Control로 어디서나 로컬 세션 계속하기","description":"Remote Control을 사용해 전화기, 태블릿, 또는 모든 브라우저에서 로컬 Claude Code 세션을 이어서 작업하세요. claude.ai/code 및 Claude 모바일 앱에서 작동합니다."},"headers":[],"relativePath":"remote-control.md","filePath":"remote-control.md","lastUpdated":1776205703000}'),d={name:"remote-control.md"};function r(c,e,s,i,n,h){return t(),a("div",null,[...e[0]||(e[0]=[l(`<h1 id="remote-control로-어디서나-로컬-세션-계속하기" tabindex="-1">Remote Control로 어디서나 로컬 세션 계속하기 <a class="header-anchor" href="#remote-control로-어디서나-로컬-세션-계속하기" aria-label="Permalink to &quot;Remote Control로 어디서나 로컬 세션 계속하기&quot;">​</a></h1><blockquote><p>Remote Control을 사용하면 전화기, 태블릿, 또는 모든 브라우저에서 로컬 Claude Code 세션을 이어서 작업할 수 있습니다. claude.ai/code 및 Claude 모바일 앱에서 작동합니다.</p></blockquote><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Remote Control은 모든 플랜에서 사용 가능합니다. Team 및 Enterprise 플랜에서는 기본적으로 비활성화되어 있으며, 관리자가 <a href="https://claude.ai/admin-settings/claude-code" target="_blank" rel="noreferrer">Claude Code 관리자 설정</a>에서 Remote Control 토글을 활성화해야 합니다.</p></div><p>Remote Control은 <a href="https://claude.ai/code" target="_blank" rel="noreferrer">claude.ai/code</a>나 <a href="https://apps.apple.com/us/app/claude-by-anthropic/id6473753684" target="_blank" rel="noreferrer">iOS</a> 및 <a href="https://play.google.com/store/apps/details?id=com.anthropic.claude" target="_blank" rel="noreferrer">Android</a>용 Claude 앱을 사용자의 로컬 머신에서 실행 중인 Claude Code 세션에 연결합니다. 책상에서 작업을 시작하고, 소파에서 전화기로 또는 다른 컴퓨터의 브라우저에서 계속 작업할 수 있습니다.</p><p>Remote Control 세션을 시작하면 Claude는 전체 시간 동안 로컬에서만 실행되므로, 아무것도 클라우드로 이동하지 않습니다. Remote Control을 사용하면 다음이 가능합니다:</p><ul><li><strong>전체 로컬 환경을 원격으로 사용</strong>: 파일 시스템, <a href="/claude-code-docs-ko/mcp.html">MCP 서버</a>, 도구, 프로젝트 설정이 모두 유지됩니다</li><li><strong>두 기기에서 동시에 작업</strong>: 대화가 연결된 모든 기기에서 동기화되므로 터미널, 브라우저, 전화기에서 번갈아가며 메시지를 보낼 수 있습니다</li><li><strong>중단에서 복구</strong>: 노트북이 절전 상태가 되거나 네트워크가 끊겨도, 머신이 다시 온라인 상태가 되면 세션이 자동으로 재연결됩니다</li></ul><p>클라우드 인프라에서 실행되는 <a href="/claude-code-docs-ko/claude-code-on-the-web.html">웹의 Claude Code</a>와 달리, Remote Control 세션은 사용자의 로컬 머신에서 직접 실행되어 로컬 파일 시스템과 상호작용합니다. 웹 및 모바일 인터페이스는 해당 로컬 세션을 보는 창일 뿐입니다.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Remote Control은 Claude Code v2.1.51 이상이 필요합니다. <code>claude --version</code>으로 버전을 확인하세요.</p></div><p>이 페이지에서는 설정 방법, 세션 시작 및 연결 방법, Remote Control과 웹의 Claude Code의 차이점을 설명합니다.</p><h2 id="요구-사항" tabindex="-1">요구 사항 <a class="header-anchor" href="#요구-사항" aria-label="Permalink to &quot;요구 사항&quot;">​</a></h2><p>Remote Control을 사용하기 전에 환경이 다음 조건을 충족하는지 확인하세요:</p><ul><li><strong>구독</strong>: Pro, Max, Team, Enterprise 플랜에서 사용 가능합니다. API 키는 지원되지 않습니다. Team 및 Enterprise 플랜에서는 관리자가 먼저 <a href="https://claude.ai/admin-settings/claude-code" target="_blank" rel="noreferrer">Claude Code 관리자 설정</a>에서 Remote Control 토글을 활성화해야 합니다.</li><li><strong>인증</strong>: <code>claude</code>를 실행하고 <code>/login</code>을 사용하여 아직 로그인하지 않았다면 claude.ai를 통해 로그인하세요.</li><li><strong>워크스페이스 신뢰</strong>: 프로젝트 디렉토리에서 <code>claude</code>를 최소 한 번 실행하여 워크스페이스 신뢰 대화상자에 동의하세요.</li></ul><h2 id="remote-control-세션-시작하기" tabindex="-1">Remote Control 세션 시작하기 <a class="header-anchor" href="#remote-control-세션-시작하기" aria-label="Permalink to &quot;Remote Control 세션 시작하기&quot;">​</a></h2><p>Remote Control 세션은 CLI 또는 VS Code 익스텐션에서 시작할 수 있습니다. CLI는 세 가지 호출 모드를 제공하며, VS Code는 <code>/remote-control</code> 명령을 사용합니다.</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-BkvPb" id="tab-rJcYlya" checked><label data-title="서버 모드" for="tab-rJcYlya">서버 모드</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 프로젝트 디렉토리로 이동 후 실행:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remote-control</span></span></code></pre></div></div></div><p><strong>서버 모드</strong>: 프로젝트 디렉토리로 이동하여 다음을 실행합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remote-control</span></span></code></pre></div><p>이 프로세스는 서버 모드로 터미널에서 실행 상태를 유지하며 원격 연결을 기다립니다. <a href="#다른-기기에서-연결하기">다른 기기에서 연결</a>하는 데 사용할 수 있는 세션 URL을 표시하며, 스페이스바를 누르면 전화기에서 빠르게 접근할 수 있는 QR 코드를 표시합니다. 원격 세션이 활성화된 동안 터미널은 연결 상태와 도구 활동을 표시합니다.</p><p>사용 가능한 플래그:</p><table tabindex="0"><thead><tr><th>플래그</th><th>설명</th></tr></thead><tbody><tr><td><code>--name &quot;My Project&quot;</code></td><td>claude.ai/code의 세션 목록에 표시되는 사용자 지정 세션 제목을 설정합니다.</td></tr><tr><td><code>--remote-control-session-name-prefix &lt;prefix&gt;</code></td><td>명시적인 이름이 설정되지 않았을 때 자동 생성된 세션 이름의 접두사입니다. 기본값은 머신의 호스트명이며 <code>myhost-graceful-unicorn</code>과 같은 이름을 생성합니다. 동일한 효과를 위해 <code>CLAUDE_REMOTE_CONTROL_SESSION_NAME_PREFIX</code>를 설정할 수 있습니다.</td></tr><tr><td><code>--spawn &lt;mode&gt;</code></td><td>서버가 세션을 생성하는 방식입니다.<br>• <code>same-dir</code> (기본값): 모든 세션이 현재 작업 디렉토리를 공유하므로 동일한 파일을 편집할 경우 충돌이 발생할 수 있습니다.<br>• <code>worktree</code>: 각 온디맨드 세션은 자체 <a href="/claude-code-docs-ko/common-workflows.html#run-parallel-claude-code-sessions-with-git-worktrees">git worktree</a>를 가집니다. git 저장소가 필요합니다.<br>• <code>session</code>: 단일 세션 모드입니다. 정확히 하나의 세션만 제공하고 추가 연결을 거부합니다. 시작 시에만 설정 가능합니다.<br>런타임에 <code>w</code>를 눌러 <code>same-dir</code>과 <code>worktree</code> 사이를 전환합니다.</td></tr><tr><td><code>--capacity &lt;N&gt;</code></td><td>최대 동시 세션 수입니다. 기본값은 32입니다. <code>--spawn=session</code>과 함께 사용할 수 없습니다.</td></tr><tr><td><code>--verbose</code></td><td>상세한 연결 및 세션 로그를 표시합니다.</td></tr><tr><td><code>--sandbox</code> / <code>--no-sandbox</code></td><td>파일 시스템 및 네트워크 격리를 위한 <a href="/claude-code-docs-ko/sandboxing.html">샌드박싱</a>을 활성화하거나 비활성화합니다. 기본적으로 비활성화되어 있습니다.</td></tr></tbody></table><p><strong>대화형 세션</strong>: Remote Control이 활성화된 일반 대화형 Claude Code 세션을 시작하려면 <code>--remote-control</code> 플래그(또는 <code>--rc</code>)를 사용하세요:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --remote-control</span></span></code></pre></div><p>세션 이름을 선택적으로 전달할 수 있습니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --remote-control</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;My Project&quot;</span></span></code></pre></div><p>이를 통해 터미널에서 완전한 대화형 세션을 사용하면서 claude.ai나 Claude 앱에서도 제어할 수 있습니다. 서버 모드의 <code>claude remote-control</code>과 달리, 세션이 원격으로도 사용 가능한 동안 로컬에서 메시지를 입력할 수 있습니다.</p><p><strong>기존 세션에서</strong>: 이미 Claude Code 세션에 있고 원격으로 계속하려면 <code>/remote-control</code>(또는 <code>/rc</code>) 명령을 사용하세요:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/remote-control</span></span></code></pre></div><p>사용자 지정 세션 제목을 설정하려면 인수로 이름을 전달하세요:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/remote-control My Project</span></span></code></pre></div><p>이는 현재 대화 기록을 이어받아 Remote Control 세션을 시작하고, <a href="#다른-기기에서-연결하기">다른 기기에서 연결</a>하는 데 사용할 수 있는 세션 URL과 QR 코드를 표시합니다. <code>--verbose</code>, <code>--sandbox</code>, <code>--no-sandbox</code> 플래그는 이 명령과 함께 사용할 수 없습니다.</p><p><strong>VS Code</strong>: <a href="/claude-code-docs-ko/vs-code.html">Claude Code VS Code 익스텐션</a>에서 프롬프트 상자에 <code>/remote-control</code> 또는 <code>/rc</code>를 입력하거나, <code>/</code>로 명령 메뉴를 열고 선택하세요. Claude Code v2.1.79 이상이 필요합니다.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/remote-control</span></span></code></pre></div><p>프롬프트 상자 위에 연결 상태를 보여주는 배너가 나타납니다. 연결되면 배너에서 <strong>브라우저에서 열기</strong>를 클릭하여 세션으로 직접 이동하거나 <a href="https://claude.ai/code" target="_blank" rel="noreferrer">claude.ai/code</a>의 세션 목록에서 찾을 수 있습니다. 세션 URL도 대화에 게시됩니다.</p><p>연결을 해제하려면 배너의 닫기 아이콘을 클릭하거나 <code>/remote-control</code>을 다시 실행하세요.</p><p>CLI와 달리, VS Code 명령은 이름 인수를 허용하거나 QR 코드를 표시하지 않습니다. 세션 제목은 대화 기록이나 첫 번째 프롬프트에서 파생됩니다.</p><h3 id="다른-기기에서-연결하기" tabindex="-1">다른 기기에서 연결하기 <a class="header-anchor" href="#다른-기기에서-연결하기" aria-label="Permalink to &quot;다른 기기에서 연결하기&quot;">​</a></h3><p>Remote Control 세션이 활성화되면 다른 기기에서 연결하는 몇 가지 방법이 있습니다:</p><ul><li><strong>세션 URL 열기</strong>: 모든 브라우저에서 세션 URL을 열어 <a href="https://claude.ai/code" target="_blank" rel="noreferrer">claude.ai/code</a>의 세션으로 직접 이동합니다.</li><li><strong>QR 코드 스캔</strong>: 세션 URL 옆에 표시된 QR 코드를 스캔하여 Claude 앱에서 직접 열 수 있습니다. <code>claude remote-control</code>에서 스페이스바를 눌러 QR 코드 표시를 전환하세요.</li><li><strong><a href="https://claude.ai/code" target="_blank" rel="noreferrer">claude.ai/code</a> 또는 Claude 앱 열기</strong>: 세션 목록에서 이름으로 세션을 찾으세요. Remote Control 세션은 온라인일 때 초록색 상태 점이 있는 컴퓨터 아이콘을 표시합니다.</li></ul><p>원격 세션 제목은 다음 순서로 선택됩니다:</p><ol><li><code>--name</code>, <code>--remote-control</code>, 또는 <code>/remote-control</code>에 전달한 이름</li><li><code>/rename</code>으로 설정한 제목</li><li>기존 대화 기록의 마지막 의미 있는 메시지</li><li><code>myhost-graceful-unicorn</code>과 같은 자동 생성 이름 (여기서 <code>myhost</code>는 머신의 호스트명이거나 <code>--remote-control-session-name-prefix</code>로 설정한 접두사)</li></ol><p>명시적인 이름을 설정하지 않은 경우, 프롬프트를 전송하면 제목이 업데이트됩니다.</p><p>환경에 이미 활성 세션이 있는 경우, 계속할지 새로 시작할지 묻는 메시지가 표시됩니다.</p><p>아직 Claude 앱이 없다면, Claude Code 내에서 <code>/mobile</code> 명령을 사용하여 <a href="https://apps.apple.com/us/app/claude-by-anthropic/id6473753684" target="_blank" rel="noreferrer">iOS</a> 또는 <a href="https://play.google.com/store/apps/details?id=com.anthropic.claude" target="_blank" rel="noreferrer">Android</a> 다운로드 QR 코드를 표시하세요.</p><h3 id="모든-세션에-remote-control-활성화하기" tabindex="-1">모든 세션에 Remote Control 활성화하기 <a class="header-anchor" href="#모든-세션에-remote-control-활성화하기" aria-label="Permalink to &quot;모든 세션에 Remote Control 활성화하기&quot;">​</a></h3><p>기본적으로 Remote Control은 <code>claude remote-control</code>, <code>claude --remote-control</code>, 또는 <code>/remote-control</code>을 명시적으로 실행할 때만 활성화됩니다. 모든 대화형 세션에서 자동으로 활성화하려면 Claude Code 내에서 <code>/config</code>를 실행하고 <strong>모든 세션에 Remote Control 활성화</strong>를 <code>true</code>로 설정하세요. 비활성화하려면 <code>false</code>로 되돌리세요.</p><p>이 설정이 켜져 있으면, 각 대화형 Claude Code 프로세스가 하나의 원격 세션을 등록합니다. 여러 인스턴스를 실행하면 각각 자체 환경과 세션을 가집니다. 단일 프로세스에서 여러 동시 세션을 실행하려면 <a href="#remote-control-세션-시작하기">서버 모드</a>를 사용하세요.</p><h2 id="연결-및-보안" tabindex="-1">연결 및 보안 <a class="header-anchor" href="#연결-및-보안" aria-label="Permalink to &quot;연결 및 보안&quot;">​</a></h2><p>로컬 Claude Code 세션은 아웃바운드 HTTPS 요청만 수행하며 머신에서 인바운드 포트를 열지 않습니다. Remote Control을 시작하면 Anthropic API에 등록하고 작업을 폴링합니다. 다른 기기에서 연결하면, 서버는 스트리밍 연결을 통해 웹 또는 모바일 클라이언트와 로컬 세션 사이에서 메시지를 라우팅합니다.</p><p>모든 트래픽은 TLS를 통해 Anthropic API를 통과하며, 이는 모든 Claude Code 세션과 동일한 전송 보안입니다. 연결은 각각 단일 목적으로 범위가 지정되고 독립적으로 만료되는 여러 단기 자격 증명을 사용합니다.</p><h2 id="remote-control-vs-웹의-claude-code" tabindex="-1">Remote Control vs 웹의 Claude Code <a class="header-anchor" href="#remote-control-vs-웹의-claude-code" aria-label="Permalink to &quot;Remote Control vs 웹의 Claude Code&quot;">​</a></h2><p>Remote Control과 <a href="/claude-code-docs-ko/claude-code-on-the-web.html">웹의 Claude Code</a>는 모두 claude.ai/code 인터페이스를 사용합니다. 핵심 차이점은 세션이 실행되는 위치입니다: Remote Control은 사용자의 로컬 머신에서 실행되므로, 로컬 MCP 서버, 도구, 프로젝트 설정이 계속 사용 가능합니다. 웹의 Claude Code는 Anthropic이 관리하는 클라우드 인프라에서 실행됩니다.</p><p>로컬 작업 중에 다른 기기에서 계속 작업하려면 Remote Control을 사용하세요. 로컬 설정 없이 작업을 시작하거나, 클론하지 않은 저장소에서 작업하거나, 여러 작업을 병렬로 실행하려면 웹의 Claude Code를 사용하세요.</p><h2 id="제한-사항" tabindex="-1">제한 사항 <a class="header-anchor" href="#제한-사항" aria-label="Permalink to &quot;제한 사항&quot;">​</a></h2><ul><li><strong>대화형 프로세스당 하나의 원격 세션</strong>: 서버 모드 외에서는, 각 Claude Code 인스턴스가 한 번에 하나의 원격 세션만 지원합니다. 단일 프로세스에서 여러 동시 세션을 실행하려면 <a href="#remote-control-세션-시작하기">서버 모드</a>를 사용하세요.</li><li><strong>로컬 프로세스가 계속 실행되어야 함</strong>: Remote Control은 로컬 프로세스로 실행됩니다. 터미널을 닫거나 VS Code를 종료하거나 <code>claude</code> 프로세스를 중지하면 세션이 종료됩니다.</li><li><strong>장시간 네트워크 중단</strong>: 머신이 깨어 있지만 약 10분 이상 네트워크에 연결할 수 없는 경우, 세션이 타임아웃되고 프로세스가 종료됩니다. <code>claude remote-control</code>을 다시 실행하여 새 세션을 시작하세요.</li><li><strong>Ultraplan이 Remote Control 연결 해제</strong>: <a href="/claude-code-docs-ko/ultraplan.html">ultraplan</a> 세션을 시작하면 활성 Remote Control 세션이 연결 해제됩니다. 두 기능 모두 claude.ai/code 인터페이스를 차지하므로 동시에 하나만 연결할 수 있습니다.</li></ul><h2 id="문제-해결" tabindex="-1">문제 해결 <a class="header-anchor" href="#문제-해결" aria-label="Permalink to &quot;문제 해결&quot;">​</a></h2><h3 id="remote-control-requires-a-claude-ai-subscription" tabindex="-1">&quot;Remote Control requires a claude.ai subscription&quot; <a class="header-anchor" href="#remote-control-requires-a-claude-ai-subscription" aria-label="Permalink to &quot;&quot;Remote Control requires a claude.ai subscription&quot;&quot;">​</a></h3><p>claude.ai 계정으로 인증되지 않았습니다. <code>claude auth login</code>을 실행하고 claude.ai 옵션을 선택하세요. 환경에 <code>ANTHROPIC_API_KEY</code>가 설정되어 있다면 먼저 해제하세요.</p><h3 id="remote-control-requires-a-full-scope-login-token" tabindex="-1">&quot;Remote Control requires a full-scope login token&quot; <a class="header-anchor" href="#remote-control-requires-a-full-scope-login-token" aria-label="Permalink to &quot;&quot;Remote Control requires a full-scope login token&quot;&quot;">​</a></h3><p><code>claude setup-token</code> 또는 <code>CLAUDE_CODE_OAUTH_TOKEN</code> 환경 변수의 장기 토큰으로 인증되었습니다. 이 토큰은 추론 전용으로 제한되어 있으며 Remote Control 세션을 설정할 수 없습니다. <code>claude auth login</code>을 실행하여 전체 범위의 세션 토큰으로 인증하세요.</p><h3 id="unable-to-determine-your-organization-for-remote-control-eligibility" tabindex="-1">&quot;Unable to determine your organization for Remote Control eligibility&quot; <a class="header-anchor" href="#unable-to-determine-your-organization-for-remote-control-eligibility" aria-label="Permalink to &quot;&quot;Unable to determine your organization for Remote Control eligibility&quot;&quot;">​</a></h3><p>캐시된 계정 정보가 오래되었거나 불완전합니다. <code>claude auth login</code>을 실행하여 갱신하세요.</p><h3 id="remote-control-is-not-yet-enabled-for-your-account" tabindex="-1">&quot;Remote Control is not yet enabled for your account&quot; <a class="header-anchor" href="#remote-control-is-not-yet-enabled-for-your-account" aria-label="Permalink to &quot;&quot;Remote Control is not yet enabled for your account&quot;&quot;">​</a></h3><p>특정 환경 변수가 있을 때 적격성 확인이 실패할 수 있습니다:</p><ul><li><code>CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC</code> 또는 <code>DISABLE_TELEMETRY</code>: 설정을 해제하고 다시 시도하세요.</li><li><code>CLAUDE_CODE_USE_BEDROCK</code>, <code>CLAUDE_CODE_USE_VERTEX</code>, 또는 <code>CLAUDE_CODE_USE_FOUNDRY</code>: Remote Control은 claude.ai 인증이 필요하며 서드파티 공급자와는 작동하지 않습니다.</li></ul><p>이 중 아무것도 설정되지 않은 경우, <code>/logout</code>한 다음 <code>/login</code>을 실행하여 갱신하세요.</p><h3 id="remote-control-is-disabled-by-your-organization-s-policy" tabindex="-1">&quot;Remote Control is disabled by your organization&#39;s policy&quot; <a class="header-anchor" href="#remote-control-is-disabled-by-your-organization-s-policy" aria-label="Permalink to &quot;&quot;Remote Control is disabled by your organization&#39;s policy&quot;&quot;">​</a></h3><p>이 오류는 세 가지 원인이 있습니다. 먼저 <code>/status</code>를 실행하여 사용 중인 로그인 방법과 구독을 확인하세요.</p><ul><li><strong>API 키나 Console 계정으로 인증됨</strong>: Remote Control은 claude.ai OAuth가 필요합니다. <code>/login</code>을 실행하고 claude.ai 옵션을 선택하세요. 환경에 <code>ANTHROPIC_API_KEY</code>가 설정되어 있다면 해제하세요.</li><li><strong>Team 또는 Enterprise 관리자가 활성화하지 않음</strong>: Remote Control은 이 플랜에서 기본적으로 비활성화되어 있습니다. 관리자가 <a href="https://claude.ai/admin-settings/claude-code" target="_blank" rel="noreferrer">claude.ai/admin-settings/claude-code</a>에서 <strong>Remote Control</strong> 토글을 켜서 활성화할 수 있습니다. 이는 <a href="/claude-code-docs-ko/permissions.html#managed-only-settings">관리되는 설정</a> 키가 아닌 서버 측 조직 설정입니다.</li><li><strong>관리자 토글이 회색으로 표시됨</strong>: 조직에 Remote Control과 호환되지 않는 데이터 보존 또는 규정 준수 설정이 있습니다. 관리자 패널에서 변경할 수 없습니다. 옵션을 논의하려면 Anthropic 지원에 문의하세요.</li></ul><h3 id="remote-credentials-fetch-failed" tabindex="-1">&quot;Remote credentials fetch failed&quot; <a class="header-anchor" href="#remote-credentials-fetch-failed" aria-label="Permalink to &quot;&quot;Remote credentials fetch failed&quot;&quot;">​</a></h3><p>Claude Code가 연결을 설정하기 위해 Anthropic API에서 단기 자격 증명을 가져올 수 없었습니다. <code>--verbose</code>와 함께 다시 실행하여 전체 오류를 확인하세요:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remote-control</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --verbose</span></span></code></pre></div><p>일반적인 원인:</p><ul><li>로그인하지 않음: <code>claude</code>를 실행하고 <code>/login</code>을 사용하여 claude.ai 계정으로 인증하세요. API 키 인증은 Remote Control에서 지원되지 않습니다.</li><li>네트워크 또는 프록시 문제: 방화벽이나 프록시가 아웃바운드 HTTPS 요청을 차단할 수 있습니다. Remote Control은 포트 443에서 Anthropic API에 접근해야 합니다.</li><li>세션 생성 실패: <code>Session creation failed — see debug log</code>도 표시된다면 설정의 초기 단계에서 실패한 것입니다. 구독이 활성화되어 있는지 확인하세요.</li></ul><h2 id="올바른-접근-방식-선택하기" tabindex="-1">올바른 접근 방식 선택하기 <a class="header-anchor" href="#올바른-접근-방식-선택하기" aria-label="Permalink to &quot;올바른 접근 방식 선택하기&quot;">​</a></h2><p>Claude Code는 터미널에 없을 때 작업하는 여러 방법을 제공합니다. 작업을 트리거하는 방법, Claude가 실행되는 위치, 필요한 설정이 다릅니다.</p><table tabindex="0"><thead><tr><th style="text-align:left;"></th><th style="text-align:left;">트리거</th><th style="text-align:left;">Claude 실행 위치</th><th style="text-align:left;">설정</th><th style="text-align:left;">최적 사용 사례</th></tr></thead><tbody><tr><td style="text-align:left;"><a href="/claude-code-docs-ko/desktop.html#sessions-from-dispatch">Dispatch</a></td><td style="text-align:left;">Claude 모바일 앱에서 작업 메시지 전송</td><td style="text-align:left;">사용자의 머신 (Desktop)</td><td style="text-align:left;"><a href="https://support.claude.com/en/articles/13947068" target="_blank" rel="noreferrer">모바일 앱과 Desktop 페어링</a></td><td style="text-align:left;">자리를 비웠을 때 작업 위임, 최소 설정</td></tr><tr><td style="text-align:left;"><a href="/claude-code-docs-ko/remote-control.html">Remote Control</a></td><td style="text-align:left;"><a href="https://claude.ai/code" target="_blank" rel="noreferrer">claude.ai/code</a> 또는 Claude 모바일 앱에서 실행 중인 세션 제어</td><td style="text-align:left;">사용자의 머신 (CLI 또는 VS Code)</td><td style="text-align:left;"><code>claude remote-control</code> 실행</td><td style="text-align:left;">다른 기기에서 진행 중인 작업 제어</td></tr><tr><td style="text-align:left;"><a href="/claude-code-docs-ko/channels.html">Channels</a></td><td style="text-align:left;">Telegram, Discord 같은 채팅 앱이나 자체 서버에서 이벤트 푸시</td><td style="text-align:left;">사용자의 머신 (CLI)</td><td style="text-align:left;"><a href="/claude-code-docs-ko/channels.html#quickstart">채널 플러그인 설치</a> 또는 <a href="/claude-code-docs-ko/channels-reference.html">직접 빌드</a></td><td style="text-align:left;">CI 실패나 채팅 메시지 같은 외부 이벤트에 반응</td></tr><tr><td style="text-align:left;"><a href="/claude-code-docs-ko/slack.html">Slack</a></td><td style="text-align:left;">팀 채널에서 <code>@Claude</code> 언급</td><td style="text-align:left;">Anthropic 클라우드</td><td style="text-align:left;"><a href="/claude-code-docs-ko/claude-code-on-the-web.html">웹의 Claude Code</a> 활성화로 <a href="/claude-code-docs-ko/slack.html#setting-up-claude-code-in-slack">Slack 앱 설치</a></td><td style="text-align:left;">팀 채팅에서 PR 및 리뷰</td></tr><tr><td style="text-align:left;"><a href="/claude-code-docs-ko/scheduled-tasks.html">예약 작업</a></td><td style="text-align:left;">일정 설정</td><td style="text-align:left;"><a href="/claude-code-docs-ko/scheduled-tasks.html">CLI</a>, <a href="/claude-code-docs-ko/desktop-scheduled-tasks.html">Desktop</a>, 또는 <a href="/claude-code-docs-ko/web-scheduled-tasks.html">클라우드</a></td><td style="text-align:left;">빈도 선택</td><td style="text-align:left;">일일 리뷰 같은 반복 자동화</td></tr></tbody></table><h2 id="관련-리소스" tabindex="-1">관련 리소스 <a class="header-anchor" href="#관련-리소스" aria-label="Permalink to &quot;관련 리소스&quot;">​</a></h2><ul><li><a href="/claude-code-docs-ko/claude-code-on-the-web.html">웹의 Claude Code</a>: 로컬 머신 대신 Anthropic이 관리하는 클라우드 환경에서 세션 실행</li><li><a href="/claude-code-docs-ko/ultraplan.html">Ultraplan</a>: 터미널에서 클라우드 계획 세션을 시작하고 브라우저에서 계획 검토</li><li><a href="/claude-code-docs-ko/channels.html">Channels</a>: Telegram, Discord, 또는 iMessage를 세션으로 전달하여 자리를 비운 동안 Claude가 메시지에 반응</li><li><a href="/claude-code-docs-ko/desktop.html#sessions-from-dispatch">Dispatch</a>: 전화기에서 작업을 메시지로 전송하면 Desktop 세션이 처리</li><li><a href="/claude-code-docs-ko/authentication.html">인증</a>: <code>/login</code> 설정 및 claude.ai 자격 증명 관리</li><li><a href="/claude-code-docs-ko/cli-reference.html">CLI 참조</a>: <code>claude remote-control</code>을 포함한 전체 플래그 및 명령 목록</li><li><a href="/claude-code-docs-ko/security.html">보안</a>: Remote Control 세션이 Claude Code 보안 모델에 맞는 방식</li><li><a href="/claude-code-docs-ko/data-usage.html">데이터 사용</a>: 로컬 및 원격 세션 중 Anthropic API를 통해 흐르는 데이터</li></ul>`,78)])])}const m=o(d,[["render",r]]);export{p as __pageData,m as default};
